/**
 * @param {Config} config
 * @param {Context} context
 * Do not edit this comment or parameter types. Required for code suggestions
*/
exports.main = function (config, context) {
    config.addScriptLine( "enable" );
    config.addScriptLine( "configure" );
    //Activate SNMP
    config.addScriptLine( "snmp-server" );
    //Create SNMPv3User
    config.addScriptLine( "snmp-server user snmpclient sha 6850Dorn priv aes 6850Dorn" ); // USERNAME = SNMP Username ;  PASSWORD = Password of Choice
    //Create SNMPv3Group
    config.addScriptLine( "snmp-server security-to-group model v3 name snmpclient group snmpv3" ); // USERNAME = SNMP Username; GROUPNAME = SNMP Group Name
    //Create SNMPv3View
    config.addScriptLine( "snmp-server view snmpview .1 include " ); // VIEWNAME = Name of SNMP VIEW ; OID = OID Subtree (e.g. .1 for all) ; VIEWTYPE = included or excluded
    //Create SNMPv3Access
    config.addScriptLine( "snmp-server access snmpv3 model v3 level priv read snmpview write snmpview" ); // GROUPNAME = SNMP Group Name ; VIEWNAME = Name of SNMP VIEW




    config.addScriptLine( "exit" );

};
